+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    RecursiveInput<TWrapped>,
+    RecursiveOutput<TWrapped>,
+    InferIssue<TWrapped>
+  > {
+  /** The schema type. */
+  readonly type: 'recursive';
+  /** The schema reference. */
+  readonly reference: typeof recursive;
+  /** The wrapped schema. */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * A placeholder for a self reference in a recursive schema.
+ */
+export const Recur: BaseSchema<Recur, Recur, BaseIssue<unknown>> = {
+  kind: 'schema',
+  type: 'recur',
+  reference: () => Recur,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'() {
+    throw new Error('The Recur placeholder must be wrapped with recursive().');
+  },
+};
+
+/**
+ * Resolves recursive placeholders in a schema.
+ */
+function resolveRecur<TValue>(
+  value: TValue,
+  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+  references = new WeakMap<object, object>()
+): TValue {
+  if (value === Recur) {
+    return schema as TValue;
+  }
+  if (typeof value !== 'object' || value === null) {
+    return value;
+  }
+  const reference = references.get(value);
+  if (reference) {
+    return reference as TValue;
+  }
+  if (Array.isArray(value)) {
+    const clone: unknown[] = [];
+    references.set(value, clone);
+    for (const item of value) {
+      clone.push(resolveRecur(item, schema, references));
+    }
+    return clone as TValue;
+  }
+  if (Object.getPrototypeOf(value) !== Object.prototype) {
+    return value;
+  }
+  const clone = {} as Record<PropertyKey, unknown>;
+  references.set(value, clone);
+  for (const key of Reflect.ownKeys(value)) {
+    const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+    if ('value' in descriptor) {
+      descriptor.value = resolveRecur(descriptor.value, schema, references);
+    }
+    Object.defineProperty(clone, key, descriptor);
+  }
+  return clone as TValue;
+}
+
+/**
+ * Creates a recursive schema.
+ *
+ * @param wrapped The schema containing recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  let schema: RecursiveSchema<TWrapped>;
+  const resolved = resolveRecur(wrapped, {
+    get '~run'(...args) {
+      return schema['~run'](...args);
+    },
+  } as BaseSchema<unknown, unknown, BaseIssue<unknown>>);
+  schema = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: 'unknown',
+    async: false,
+    wrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return resolved['~run'](dataset, config);
+    },
+  };
+  return schema;
