+describe('recursive', () => {
+  test('should resolve recursive placeholders in objects and arrays', () => {
+    const schema = recursive(
+      object({ value: string(), children: array(Recur) })
+    );
+
+    expect(
+      parse(schema, {
+        value: 'root',
+        children: [{ value: 'child', children: [] }],
+      })
+    ).toStrictEqual({
+      value: 'root',
+      children: [{ value: 'child', children: [] }],
+    });
+  });
+
+  test('should resolve recursive placeholders in record, map and set values', () => {
+    const recordSchema = recursive(record(string(), Recur));
+    const mapSchema = recursive(map(string(), Recur));
+    const setSchema = recursive(set(Recur));
+
+    expect(parse(recordSchema, { child: {} })).toStrictEqual({ child: {} });
+    expect(parse(mapSchema, new Map([['child', new Map()]]))).toStrictEqual(
+      new Map([['child', new Map()]])
+    );
+    expect(parse(setSchema, new Set([new Set()]))).toStrictEqual(
+      new Set([new Set()])
+    );
+  });
+
+  test('should resolve recursive placeholders through pipe and intersect', () => {
+    const piped = recursive(
+      pipe(object({ child: optional(Recur) }), transform((value) => value))
