+      intersect([
+        object({ value: string() }),
+        object({ child: optional(Recur) }),
+      ])
+    );
+
+    expect(parse(piped, { child: {} })).toStrictEqual({ child: {} });
+    expect(parse(intersected, { value: 'root', child: { value: 'child' } }))
